public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    if (length < 2) {
        throw new IllegalArgumentException("Input should be at least 2 bytes long");
    }

    long result = 0;
    boolean stillPadding = true;
    int end = offset + length;
    int start = offset;

    // Check for all NULs (missing fields)
    boolean allNuls = true;
    for (int i = start; i < end; i++) {
        if (buffer[i] != 0) {
            allNuls = false;
            break;
        }
    }
    if (allNuls) {
        return 0L;
    }

    for (int i = start; i < end; i++) {
        final byte currentByte = buffer[i];
        if (stillPadding) {
            if (currentByte == (byte) ' ' || currentByte == '0') {
                continue;
            }
            if (currentByte < '0' || currentByte > '7') {
                throw new IllegalArgumentException(
                        exceptionMessage(buffer, offset, length, start, currentByte));
            }
            stillPadding = false;
        }

        if (currentByte < '0' || currentByte > '7') {
            throw new IllegalArgumentException(
                    exceptionMessage(buffer, offset, length, start, currentByte));
        }

        result = (result << 3) + (currentByte - '0'); // convert from ASCII
    }

    // Verify the last byte is a space or NUL
    byte lastByte = buffer[end - 1];
    if (!(lastByte == (byte) ' ' || lastByte == 0)) {
        throw new IllegalArgumentException("Input must end with space or NUL");
    }

    return result;
}
